### 安装`vue-awesome-mui`

```bash
npm install vue-awesome-mui --save
```

### 更改`main.js`

```javascript
import Mui from 'vue-awesome-mui';
Vue.use(Mui);
```

### 更改`index.html`
```html
<script>
  
    mui.init({
      keyEventBind: {
        backbutton: true //关闭back按键监听
      }
    });
     //首页返回键处理
     //处理逻辑：1秒内，连续两次按返回键，则退出应用；
    var first = null;
mui.back = function () {
    //首次按键，提示 再按一次退出应用
    if (!first) {
    first = new Date().getTime();//记录第一次按下回退键的时间
    mui.toast('再按一次退出应用');//给出提示
    history.go(-1)//回退到上一页面
    setTimeout(function () {//1s中后清除
        first = null;
    }, 1000);
    } else {
    if (new Date().getTime() - first < 1000) {//如果两次按下的时间小于1s，
        plus.runtime.quit();//那么就退出app

    }
    }
};
</script>
```

[官方API](https://router.vuejs.org/zh/)

## 第一步 引入vue-router包

`npm install vue-router --save`

## 第二步 配置路由

```javascript
//配置路由
const routes = [
    {path: '/home', component: Home},
    {path: '/news', component: News},
    {path: '/', redirect: '/home'}   //重定向  {path: '/*', redirect: '/home'}   //重定向
];
```

## 第三步 实例化`VueRouter`对象

```javascript
const router = new VueRouter({
			routes,//routes:routes
			linkActiveClass: 'active'  //路由激活时的样式
		});
```

注意：**`VueRouter`中的`routes`如果省略k-v格式，则必须叫`routes`，如果不省略，则key必须叫`routes`**

## 第四步 在组件`vue`实例中引入路由

```javascript
vm = new Vue({
        el:'#my',
        router,
        data:{
        }
    });
```

## 第五步 配置HTML

```html
 <!-- 使用 router-link 组件来导航. -->
<!-- 通过传入 `to` 属性指定链接. -->
<!-- <router-link> 默认会被渲染成一个 `<a>` 标签 -->
<router-link to="/home">home</router-link>
<router-link to="/news">news</router-link>
 <!-- 路由出口 -->
<!-- 路由匹配到的组件将渲染在这里 -->
<router-view></router-view>
```

## 完整示例如下

```html
<!DOCTYPE html>
<html>
<head>
	<title>vue-router</title>
	<script src="./node_modules/vue/dist/vue.js"></script>
	<script src="./node_modules/vue-router/dist/vue-router.js"></script>
	<style>
		/*.router-link-active {
			color: #f60;
		}*/
		.active {
			color: #f60;
		}
	</style>
	<script>
		// 定义组件
		var Home = {
			template: '#home'
		}
		var News = {
			template: '#news'
		}
		//配置路由
		const routes = [
			{path: '/home', component: Home},
			{path: '/news', component: News},
			{path: '/', redirect: '/home'}   //重定向  {path: '/*', redirect: '/home'}   //重定向
		];
		const router = new VueRouter({
			routes,//routes:routes
			linkActiveClass: 'active' 
		});
		
		var vm = null;
		window.onload=function(){
			vm = new Vue({
				el:'#my',
				router,
				data:{
				}
			});
		}
	</script>
</head>
<template id="home">
	<div>
		<h3>组件home</h3>
	</div>
</template>
<template id="news">
	<div>
		<h3>组件news</h3>
	</div>
</template>

<body>
	<div id="my">
		<router-link to="/home">home</router-link>
		<router-link to="/news">news</router-link>
		<div>
			<router-view></router-view>
		</div>
	</div>
</body>
</html>
```

## 父组件传递数据到子组件

```javascript
var vm = new Vue({
    el:'#my',// 2.0不允许挂载到html,body元素上
    data:{
        flag:'my-hello'
    },
    components: { //局部组件
        'my-parent': {
            template:'#parent',
            data(){
                return {
                    page:40,
                    pname:'parent',
                }
            },
            components:{
                'my-child':{//子组件
                    data(){
                        return {
                            cage:'10',
                            cname:'child'
                        }
                    },
                    template:'#child',
                    props:['message','message2'] , //父传到子
                    /*props:{ //也可以是对象，允许配置高级设置，如类型判断、数据校验、设置默认值
                        message:String,   //指定类型
                        message2:String,
                        name:{
                            type:String,
                            required:false
                        },
                        age:{                  //传的参数进行校验
                            type:Number,
                            required:false,   //是否必须
                            default:10,       //默认值
                            validator:function(value){   //是否进行校验
                                return value>=0;
                            }
                        },
                        user:{
                            type:Object,
                            default:function(){
                                return {id:111}
                            }
                        }
                    },*/
                }
                
            }
        }
    }
});
```

```html
<template id="parent">
	<div>
		<h3>我是父组件，访问自己的数据：姓名-{{pname}},年龄-{{page}}</h3>
		<hr>
		<!-- 父调用子 父传入子 -->
		<my-child :message="page" :message2="pname" ></my-child>
	</div>
</template>
<template id="child">
	<div>
		<h3>我是子组件，访问父的数据：姓名-{{message2}} ,年龄-{{message}}</h3>
		<h3>我是子组件，访问自己的数据：年龄-{{cage}}, 姓名-{{cname}}</h3>
	</div>
</template>
<body>
	<div id="my">
		<my-parent></my-parent>
	</div>
</body>
```

![图片](https://raw.githubusercontent.com/TaffyBlog/TaffyBlog.github.io/master/images/comp2.png)

在本例中：
1. 在子组件中定义`props`,声明`message`、`message2`
2. 在父组件的`template`中调用子组件时，使用`message`、`message2`用于传递`page`、`pname`。
3. 子组件中直接使用`message`和`message2`即可。

> 一个组件默认可以拥有任意数量的 `prop`，任何值都可以传递给任何 `prop`。在上述示例中，你会发现我们能够在组件实例中访问这个值，就像访问 `data` 中的值一样



## 子组件传递数据到父组件

```javascript
var vm = new Vue({
    el:'#my',// 2.0不允许挂载到html,body元素上
    data:{
        flag:'my-hello'
    },
    components: { //局部组件
        'my-parent': {
            template:'#parent',
            data(){
                return {
                    page:40,
                    pname:'parent',
                    cage:'',
                    cname:''
                }
            },
            methods:{
                getSubData(name,age) {
                    this.cage = age;
                    this.cname = name;
                }
            },
            components:{
                'my-child':{//子组件
                    data(){
                        return {
                            cage:'10',
                            cname:'child'
                        }
                    },
                    template:'#child',
                    methods:{
                        send(){
                            console.log(this);// 此时this为子组件实例
                            this.$emit('e-child', this.cname, this.cage); //发送数据  emit发射/发送
                        },
                    },
                    mounted(){//常用  挂载结束状态  完成挂载
                        this.send();
                    },
                }
                
            }
        }
    }
});
```

```html
<template id="parent">
	<div>
		<h3>我是父组件，访问自己的数据：姓名-{{pname}},年龄-{{page}}</h3>
		<h3 >我是父组件，接收子的数据：姓名-{{cname}}, 年龄-{{cage}}</h3>
		<hr>
		<!-- 子调用父  -->
		<my-child @e-child="getSubData"></my-child>
	</div>
</template>
<template id="child">
	<div>
		<h3>我是子组件，访问自己的数据：年龄-{{cage}}, 姓名-{{cname}}</h3>
		<button @click="send">手动将子组件的数据向上传递给父组件</button>
	</div>
</template>
<body>
	<div id="my">
		<my-parent></my-parent>
	</div>
</body>
```

![图片](https://raw.githubusercontent.com/TaffyBlog/TaffyBlog.github.io/master/images/comp2.png)


在本例中：
1. 子组件被挂载完毕时(`mounted`),执行了子组件中的`send`方法。
2. 在`send`方法中，触发了`e-child`事件，而在父组件的`template`中将`e-child`指向了`getSubData`方法,并将`cname`、`cage`传递了过去。
3. 父组件的`getSubData`接收到数据并向自身`data`赋值，数据展示完毕。
4. 除了挂载完毕时自动传递，还可以点击按钮手动传递。



## 非父子组件间的数据传递

与子传父类似，通过`emit`向另一个组件的方法发送数据。

用`vm.$on`接收数据

**vm.$on:**监听当前实例上的自定义事件。事件可以由`vm.$emit`触发。回调函数会接收所有传入事件触发函数的额外参数。

示例：

```html
<!DOCTYPE html>
<html>
<head>
	<title>非父子组件间的通信</title>
	<script src="../node_modules/vue/dist/vue.js"></script>
	<script>
		// 定义一个空对象，用于触发和监听实例
		var Bus = new Vue();
		var A = {
			template: '#a',
			data(){
				return {
					name:'aaa'
				}
			},
			methods:{
				send(){
					Bus.$emit('data-a', this.name);
				}
			}
		}
		var B = {
			template: '#b',
			data(){
				return {
					age:33
				}
			},
			methods:{
				send(){
					Bus.$emit('data-b', this.age);
				}
			}
			// mounted(){
			// 	Bus.$emit('data-b', this.age)
			// }
		}
		var C = {
			template: '#c',
			data(){
				return {
					name:'',
					age:''
				}
			},
			mounted(){
				//这种写法取不到值 因为this指向Bus
				 Bus.$on('data-a', function(name){
				 	this.name = name;
				 });
				 //箭头函数this总是指向函数定义生效时所在的对象
				// 注意：箭头函数内部不会产生新的this，即就是当前实例，回调会
				// 回调函数内部this为上面的空vue实例对象
				/*Bus.$on('data-a', name =>{
					this.name = name;
				});*/
				Bus.$on('data-b', age =>{    //$on接收
					this.age = age;
				});
			}
		}

		var vm = null;
		window.onload=function(){
			vm = new Vue({
				el:'#my',
				data:{
				},
				components: { //局部组件
					'my-a': A,
					'my-b': B,
					'my-c': C
				}
			});
		}
	</script>
</head>
<template id="a">
	<div>
		<h3>组件a：{{name}}</h3>
		<button @click="send">数据发给C</button>
	</div>
</template>
<template id="b">
	<div>
		<h3>组件b：{{age}}</h3>
		<button @click="send">数据发给C</button>
	</div>
</template>
<template id="c">
	<div>
		<h3>组件c：{{name}} {{age}}</h3>
	</div>
</template>
<body>
	<div id="my">
		<my-a></my-a>
		<my-b></my-b>
		<my-c></my-c>
	</div>
</body>
</html>
```

## 安装依赖

### 安装命令

```bash
cnpm init

cnpm i vue –s   

cnpm i -g webpack-cli

npm i -D webpack webpack-cli 

cnpm i -D webpack webpack-dev-server 
```


> I install    -s --save

预编译模板：

```bash
cnpm i -D vue-loader vue-html-loader vue-style-loader　vue-template-compiler

cnpm i -D css-loader file-loader style-loader
```


```bash
cnpm i -D babel-loader babel-core babel-preset-env
```

> 使用`-D`会安装到`devDependencies`,使用`-S`会安装到`dependencies`，分别表示生产环境和开发环境的依赖。例如`jquery`，`vue`属于项目运行的依赖插件，需要放入`dependencies`中，像`gulp`，`webpack`等打包工具，在开发时发挥作用，存在开发环境即可。


