## 自定义指令

### 作用

除了核心功能默认内置的指令 (`v-model` 和 `v-show`)，`Vue` 也允许注册自定义指令。注意，在 `Vue2.0` 中，代码复用和抽象的主要形式是组件。然而，有的情况下，你仍然需要对普通 `DOM` 元素进行底层操作，这时候就会用到自定义指令。


### 钩子函数

```javascript
// 自定义指定可操作DOM 注：必须加前缀，v-
Vue.directive('hello', {
    // 可以有参数el binding, binding中包括一些属性：name,value,
    // binding.vlaue => 绑定的变量
    // binding.expression => 表达式  v-my-directive="1+1"
    // binding.arg => 传参 v-on:click 
    // binding.modifiers => 如: v-on:click.prevent 修饰符可以有多个
    bind(el, binding){//常用
        console.log(el, binding.arg);
        el.style.color = 'red';
        alert("指令第一次绑定到元素上时调用，只调用一次，可执行初始化操作");
    },
    inserted(){
        alert("被绑定元素插入到dom中时调用");
    },
    update(){
        alert("被绑定元素所在模板更新时调用");
    },
    componentUpdated(){
        alert("被绑定元素所在模板完成一次更新周期时调用")
    },
    unbind(){
        alert("指令与元素解绑时调用，只调用一次");
    }
})
```

### 简单实例

```html
 <div id="app">
    <span v-hello>{{message}}</span><br>
    <span v-hello:foo>{{message}}</span>
</div>

``` 


```javascript
Vue.directive("hello",{
    bind:function(el,binding){
        el.style.color='red';
        console.log(el,binding.arg);
    }
})
var app = new Vue({ 
    el: '#app',
    data: {
        message: 'Hello Vue!'
    }
});
```

